const express = require('express');
const nodemailer = require('nodemailer');
const PizZip = require('pizzip');
const Docxtemplater = require('docxtemplater');
const cors = require('cors');

const app = express();
app.use(express.json());
app.use(cors());

// 👇 PASTE YOUR ORIGINAL BASE64 STRING INSIDE THESE QUOTES
const BASE64_DOCX = "";

app.post('/api/send-offer', async (req, res) => {
  // Defensive fallbacks to prevent undefined type errors
  const name = String(req.body.name || req.body.employee_name || 'Candidate').trim();
  const email = String(req.body.email || '').trim();
  const startDate = String(req.body.startDate || req.body.start_date || 'TBD').trim();
  const salary = String(req.body.salary || req.body.salary_amount || '0').trim();

  if (!email) {
    return res.status(400).json({ error: 'Recipient email parameter is required.' });
  }

  try {
    const binaryContent = Buffer.from(BASE64_DOCX, 'base64');
    const zip = new PizZip(binaryContent);
    
    // Initialize docxtemplater with an advanced functional parser.
    // This looks directly at the text value of the tag, cutting past split XML runs
    // and matching loose spaced properties or missing brace variations flawlessly.
    const doc = new Docxtemplater(zip, {
        paragraphLoop: true,
        linebreaks: true,
        parser: function(tag) {
            return {
                get: function(scope) {
                    // Normalize the tag key name to remove tracking spaces or broken tails
                    const normalizedKey = tag.replace(/[^a-zA-Z_]/g, '').trim();
                    if (normalizedKey === 'employee_name') return name;
                    if (normalizedKey === 'start_date') return startDate;
                    if (normalizedKey === 'salary_amount') return salary;
                    return scope[tag];
                }
            };
        }
    });

    // Feed fallback properties into the map context array
    doc.render({
        employee_name: name,
        start_date: startDate,
        salary_amount: salary
    });

    const updatedDocBuffer = doc.getZip().generate({
        type: 'nodebuffer',
        compression: 'DEFLATE',
    });

    // Paste this in its place:
const transporter = nodemailer.createTransport({
  host: 'smtp.gmail.com',
  port: 465,
  secure: true, // true for 465, false for other ports
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS, // Your 16-character app password (no spaces)
  },
  // This prevents Vercel's proxy from timing out the connection handshake
  connectionTimeout: 10000, 
});

    const emailHtml = `
      <p>Hi ${name},</p>
      <p>We're happy to offer you the position of Twitter Growth Assistant at FanFame Media.</p>
      <p>Your salary will be ₹${salary} per month.</p>
      <p>As a Twitter Growth Assistant, you will be responsible for managing assigned Twitter/X accounts and following lead lists provided by the company. Training and clear instructions will be provided, and your role is to complete the assigned daily tasks consistently and accurately.</p>
      <p>We're looking for someone who is reliable, consistent, able to follow instructions, comfortable with repetitive tasks, and communicates professionally.</p>
      <p>Any company accounts, systems, SOPs, lead lists, or internal information shared with you must remain confidential and may not be shared with anyone outside the company.</p>
      <p>To accept this offer, please review the attached contract, sign it, and return the signed copy by replying to this email.</p>
      <p>Upon receipt of the signed contract, we will provide further onboarding instructions and confirm your start date.</p>
      <p>We're excited to have you join the team.</p>
      <br>
      <p>Best regards,</p>
      <p>George<br>FanFame Media</p>
    `;

    const cleanFileName = `OfferLetter_${name.replace(/[^a-zA-Z0-9]/g, '_')}.docx`;

    const mailOptions = {
      from: `"George - FanFame Media" <${process.env.EMAIL_USER}>`,
      to: email,
      subject: 'Offer letter - twitter management, FanFame media',
      html: emailHtml,
      attachments: [
        {
          filename: cleanFileName,
          content: updatedDocBuffer,
        },
      ],
    };

    await transporter.sendMail(mailOptions);
    return res.status(200).json({ message: 'Success' });

  } catch (error) {
    console.error("Critical Engine Execution Fail:", error);
    // Returns an explicit 500 error if Nodemailer fails to connect so you can see it clearly
    return res.status(500).json({ error: 'Mail delivery error architecture failure.', details: error.message });
  }
});

module.exports = app;
